package com.finance.tracker.export;
import com.finance.tracker.security.UserPrincipal; import com.finance.tracker.transaction.*; import com.lowagie.text.*; import com.lowagie.text.pdf.*; import java.io.*; import java.time.*; import java.util.*; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/export") public class ExportController {private final TransactionService transactions;public ExportController(TransactionService t){transactions=t;}@GetMapping("/monthly") public ResponseEntity<byte[]> monthly(@AuthenticationPrincipal UserPrincipal u,@RequestParam int month,@RequestParam int year,@RequestParam(defaultValue="csv") String format)throws DocumentException,IOException{if(month<1||month>12)throw new IllegalArgumentException("Month must be between 1 and 12");LocalDate s=LocalDate.of(year,month,1),e=s.withDayOfMonth(s.lengthOfMonth());var list=transactions.list(u.id(),s,e,null);boolean pdf="pdf".equalsIgnoreCase(format);byte[] body=pdf?pdf(list,month,year):csv(list);String ext=pdf?"pdf":"csv";return ResponseEntity.ok().contentType(pdf?MediaType.APPLICATION_PDF:MediaType.parseMediaType("text/csv")).header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=finance-report-"+year+"-"+month+"."+ext).body(body);}
 private byte[] csv(List<TransactionService.TransactionResponse> list){StringBuilder b=new StringBuilder("Date,Type,Category,Description,Amount\\n");for(var t:list)b.append(t.date()).append(',').append(t.type()).append(',').append(q(t.category())).append(',').append(q(t.description())).append(',').append(t.amount()).append('\\n');return b.toString().getBytes(java.nio.charset.StandardCharsets.UTF_8);}private String q(String v){return "\""+(v==null?"":v.replace("\"","\"\""))+"\"";}
 private byte[] pdf(List<TransactionService.TransactionResponse> list,int month,int year)throws DocumentException{ByteArrayOutputStream out=new ByteArrayOutputStream();Document d=new Document(PageSize.A4);PdfWriter.getInstance(d,out);d.open();d.add(new Paragraph("Personal Finance Report — "+Month.of(month)+" "+year,new Font(Font.HELVETICA,18,Font.BOLD)));PdfPTable table=new PdfPTable(new float[]{2,2,2,4,2});table.setWidthPercentage(100);for(String h:List.of("Date","Type","Category","Description","Amount")){PdfPCell c=new PdfPCell(new Phrase(h));c.setBackgroundColor(java.awt.Color.LIGHT_GRAY);table.addCell(c);}for(var t:list){table.addCell(t.date().toString());table.addCell(t.type().toString());table.addCell(t.category());table.addCell(t.description()==null?"":t.description());table.addCell(t.amount().toPlainString());}d.add(table);d.close();return out.toByteArray();}}
